mapper.select:
SELECT COALESCE(SUM(points), 0)
FROM points_record
WHERE user_id = #{userId}
    AND type = #{type}
    AND create_time BETWEEN #{beginTime} AND #{endTime}

SELECT type, sum(points) AS points
FROM points_record
WHERE user_id = #{userId}
  AND create_time BETWEEN #{beginTime} AND #{endTime}
GROUP BY type;
